  "type": "LEARNING_CARD",
  "title": "Basic Music Notation: Notes and Clefs",
  "lessonText": "Understanding notes and clefs is essential for reading music.",
  "data": {
    "learningCards": [
      {
        "title": "Musical Notes",
        "content": "Notes represent sounds in music. They have different shapes and positions.",
        "layout": "standard"
      },
      {
        "title": "Clefs",
        "content": "Clefs indicate the pitch of the notes. The treble and bass clefs are the most common.",
        "layout": "standard"
      },
      {
        "title": "Note Values",
        "content": "Notes can be whole, half, quarter, eighth, etc. Each value affects the duration of the sound.",
        "layout": "standard"
      },
      {
        "title": "Reading Music",
        "content": "Notes are placed on lines and spaces. The position determines the note's name.",
        "layout": "standard"
      }
    ]
  }
}
